    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCode()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.StartsWith(result, "(212)");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFour()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.EndsWith(result, "1234");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsDash()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.Contains(result, "-");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsExactFormat()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        Assert.AreEqual("(212) 555-1234", result);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public void FormatPhoneNumber_NullInput_Throws()
    {
        _formatter.FormatPhoneNumber(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void FormatPhoneNumber_TooShort_Throws()
    {
        _formatter.FormatPhoneNumber("12345");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void FormatPhoneNumber_TooLong_Throws()
    {
        _formatter.FormatPhoneNumber("12345678901");
    }

    // ── BuildGreeting ──────────────────────────────────────────────

    [TestMethod]
    public void BuildGreeting_DefaultTitle_StartsWithDearMr()
    {
        var result = _formatter.BuildGreeting("Smith");

        StringAssert.StartsWith(result, "Dear Mr.");
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Smith");

        StringAssert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_ContainsName()
    {
        var result = _formatter.BuildGreeting("Smith");

        StringAssert.Contains(result, "Smith");
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_UsesProvidedTitle()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        StringAssert.StartsWith(result, "Dear Dr.");
        Assert.AreEqual("Dear Dr. Johnson,", result);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void BuildGreeting_WhitespaceName_Throws()
    {
        _formatter.BuildGreeting("   ");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public void BuildGreeting_NullName_Throws()
    {
        _formatter.BuildGreeting(null!);
    }

    // ── GenerateSlug ───────────────────────────────────────────────

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseDashed()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_SpecialCharacters_StripsAndJoins()
    {
        var result = _formatter.GenerateSlug("C# is Great!!!");

        Assert.AreEqual("c-is-great", result);
    }

    [TestMethod]
    public void GenerateSlug_LeadingTrailingWhitespace_Trims()
    {
        var result = _formatter.GenerateSlug("  My Post  ");

        StringAssert.StartsWith(result, "my");
        StringAssert.EndsWith(result, "post");
    }

    [TestMethod]
    public void GenerateSlug_MixedCase_ReturnsAllLowercase()
    {
        var result = _formatter.GenerateSlug("FooBar");

        Assert.AreEqual("foobar", result);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void GenerateSlug_WhitespaceOnly_Throws()
    {
        _formatter.GenerateSlug("   ");
    }

    // ── FormatCurrency ─────────────────────────────────────────────

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollar()
    {
        var result = _formatter.FormatCurrency(9.99m);

        StringAssert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_ReturnsTwoDecimals()
    {
        var result = _formatter.FormatCurrency(10m);

        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_UsesProvidedSymbol()
    {
        var result = _formatter.FormatCurrency(5.5m, "€");

        StringAssert.StartsWith(result, "€");
        Assert.AreEqual("€5.50", result);
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_FormatsCorrectly()
    {
        var result = _formatter.FormatCurrency(-42.10m);

        Assert.AreEqual("$-42.10", result);
    }
}

